  const groupIndex = Object.keys(groupWiseScore)[i];
  const questionCount = quizSet[i];

  for (let j = 0; j < questionCount; j++) {
    const questionKey = questionIndex.toString();

    if (score.hasOwnProperty(questionKey)) {
      groupWiseScore[groupIndex] += score[questionKey];
    }

