/* Height for certain classes */
.location-form,
.location-details {
    height: 48vh;
}

/* Footer styles */
.footer .v-card {
    position: absolute !important;
    bottom: 0;
    height: 65px;
    width: 100vw;
    left: -5px;
}

/* Styles for dashboard button */
.dashboard-btn {
    position: absolute;
    height: 65px;
    top: 0;
    left: 0;
}

/* Styles for new audit button */
.new-audit {
    position: absolute;
    height: 65px;
    top: 0;
    right: 0;
}

/* Styles for previous button */
.previous {
    position: absolute;
    height: 65px;
    top: 0;
    left: 0;
}

/* Button styles within dashboard button */
.dashboard-btn .v-btn {
    background: rgb(232, 240, 250);
    color: rgb(101, 144, 221);
}

/* Button styles within new audit button */
.new-audit .v-btn {
    background: rgb(34, 159, 32);
    color: white;
}

/* Button styles within previous button */
.previous .v-btn {
    background: rgb(232, 240, 250);
    color: rgb(101, 144, 221);
}

/* Styles for detail text */
.detail-text {
    font-weight: 500;
}

/* Styles for stepper */
.stepper {
    position: absolute;
    top: 0;
    padding-bottom: 10px;
    left: 80px;
    width: 700px;
}

/* Styles for follow-up button */
.follow-up {
    position: absolute;
    height: 65px;
    top: 0px;
    right: 180px;
}

/* Button styles within follow-up button */
.follow-up .v-btn {
    background: rgb(188, 0, 12);
    color: white;
}

/* Styles for next button */
.next {
    position: absolute;
    height: 65px;
    top: 0px;
    right: 0px;
    width: 150px;
}

/* Styles for log event button */
.log-event {
    position: absolute;
    height: 65px;
    top: 0px;
    right: 0px;
    width: 150px;
}

/* Button styles within next button */
.next .v-btn {
    background: rgb(36, 104, 220);
    color: white;
}

/* Button styles within log event button */
.log-event .v-btn {
    background: rgb(188, 0, 12);
    color: white;
}

/* Height settings for specific sections */
.audit-quiz,
.audit-grade {
    height: 48vh;
}

/* Styles for group score details */
.group-score-details {
    height: 45vh;
}

/* Styles for header stepper */
.header-stepper,
.header-stepper .v-card-text {
    height: 70px !important;
}

/* Styles for stepper within header stepper */
.header-stepper .stepper {
    position: absolute;
    top: 0;
    left: 130px;
    width: 700px;
}
